const payload = $json.body ?? $json;
const query = String(payload.query ?? payload.text ?? '').trim();
if (!query) {
  throw new Error('query is required');
}

const apiKey = String($env.OPENROUTER_API_KEY ?? $env.GROQ_API_KEY ?? '').trim();
if (!apiKey) {
  throw new Error('Missing OpenRouter key. Set OPENROUTER_API_KEY.');
}

const chatEndpoint = String(
  $env.OPENROUTER_CHAT_COMPLETIONS_URL ?? 'https://openrouter.ai/api/v1/chat/completions'
).trim();
if (!/^https?:\/\//i.test(chatEndpoint)) {
  throw new Error('OPENROUTER_CHAT_COMPLETIONS_URL must be a valid http(s) URL');
}

const model = String(
  $env.OPENROUTER_FITNESS_MODEL ??
    $env.OPENROUTER_CHAT_MODEL ??
    $env.OPENROUTER_MODEL ??
    'openai/gpt-4o-mini'
).trim();
if (!model) {
  throw new Error('OPENROUTER_MODEL (or OPENROUTER_FITNESS_MODEL / OPENROUTER_CHAT_MODEL) is required.');
}

const systemMessage = [
  'You are a certified fitness coach.',
  'Give concise and practical advice.',
  'If the question is risky or medical, recommend seeing a professional.'
].join('\n');

const referer = String($env.OPENROUTER_SITE_URL ?? '').trim() || 'http://localhost:5678';
const appName = String($env.OPENROUTER_APP_NAME ?? 'NutriHealth n8n').trim();

return [{
  json: {
    query,
    model,
    chatEndpoint,
    authHeader: `Bearer ${apiKey}`,
    referer,
    appName,
    messages: [
      { role: 'system', content: systemMessage },
      { role: 'user', content: query }
    ]
  }
}];

const body = $json;
const upstreamError = body?.error?.message ?? body?.error;
if (upstreamError) {
  throw new Error('OpenRouter error: ' + upstreamError);
}

const advice = String(
  body?.choices?.[0]?.message?.content ??
    body?.choices?.[0]?.text ??
    body?.output_text ??
    ''
).trim();

if (!advice) {
  throw new Error('OpenRouter returned an empty response');
}

return [{ json: { ok: true, advice } }];
